#include <bits/stdc++.h>
using namespace std;

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        vector<int> arr(n);
        long long totalSum = 0;

        // Input the array and compute the total sum
        for (int i = 0; i < n; i++) {
            cin >> arr[i];
            totalSum += arr[i];
        }

        // Sort the array
        sort(arr.begin(), arr.end());

        // Sum of the first K smallest numbers (S1) and last K largest numbers (S2)
        long long sumOfKSmallest = 0, sumOfKLargest = 0;

        for (int i = 0; i < k; i++) {
            sumOfKSmallest += arr[i];
            sumOfKLargest += arr[n - 1 - i];
        }

        // Calculate the two possible maximum differences
        long long diff1 = abs(sumOfKSmallest - (totalSum - sumOfKSmallest));
        long long diff2 = abs(sumOfKLargest - (totalSum - sumOfKLargest));

        // Output the maximum difference
        cout << max(diff1, diff2) << endl;
    }
    return 0;
}

