#include <stdio.h>
#include <stdlib.h>

// Comparator function for qsort to sort in ascending order
int compare(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        long long totalSum = 0;

        // Input the array and compute the total sum
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
            totalSum += arr[i];
        }

        // Sort the array
        qsort(arr, n, sizeof(int), compare);

        // Sum of the first K smallest numbers (S1) and last K largest numbers (S2)
        long long sumOfKSmallest = 0, sumOfKLargest = 0;

        for (int i = 0; i < k; i++) {
            sumOfKSmallest += arr[i];
            sumOfKLargest += arr[n - 1 - i];
        }

        // Calculate the two possible maximum differences
        long long diff1 = llabs(sumOfKSmallest - (totalSum - sumOfKSmallest));
        long long diff2 = llabs(sumOfKLargest - (totalSum - sumOfKLargest));

        // Output the maximum difference
        printf("%lld\n", (diff1 > diff2) ? diff1 : diff2);
    }
    return 0;
}

