import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        // Scanner for reading input
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt(); // Read number of test cases

        while (t-- > 0) {
            int n = sc.nextInt(); // Read size of array
            int k = sc.nextInt(); // Read value of K
            int[] arr = new int[n]; // Array to store the elements
            long totalSum = 0; // Variable to store the total sum of elements

            // Input the array and compute the total sum
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
                totalSum += arr[i];
            }

            // Sort the array
            Arrays.sort(arr);

            // Sum of the first K smallest numbers (S1) and last K largest numbers (S2)
            long sumOfKSmallest = 0, sumOfKLargest = 0;

            for (int i = 0; i < k; i++) {
                sumOfKSmallest += arr[i]; // Smallest K numbers
                sumOfKLargest += arr[n - 1 - i]; // Largest K numbers
            }

            // Calculate the two possible maximum differences
            long diff1 = Math.abs(sumOfKSmallest - (totalSum - sumOfKSmallest));
            long diff2 = Math.abs(sumOfKLargest - (totalSum - sumOfKLargest));

            // Output the maximum difference
            System.out.println(Math.max(diff1, diff2));
        }

        sc.close(); // Close the scanner
    }
}

