    let index = 0;
    const t = parseInt(input[index++]);

    for (let test = 0; test < t; test++) {
        let [n, k] = input[index++].split(' ').map(Number);
        let arr = input[index++].split(' ').map(Number);

        let totalSum = arr.reduce((acc, num) => acc + num, 0);

        // Sort the array in ascending order
        arr.sort((a, b) => a - b);

        // Sum of the first K smallest numbers and last K largest numbers
        let sumOfKSmallest = 0, sumOfKLargest = 0;

        for (let i = 0; i < k; i++) {
            sumOfKSmallest += arr[i];
            sumOfKLargest += arr[n - 1 - i];
